const raw = $input.first().json;
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
if (!data.employee) throw new Error('hr_generate: не переданы данные employee. Получено: ' + JSON.stringify(raw));
if (!data.violation) throw new Error('hr_generate: не переданы данные violation.');
data.scenario = data.scenario || 'progul_ochny';
return [{ json: {
  context: data,
  violationDate: data.violation.date,
  discoveryDate: data.violation.discoveryDate
} }];

const r = $input.first().json;
const prev = $('Нормализовать данные').first().json;
return [{ json: {
  context: prev.context,
  dates: {
    isExpired: r.is_expired === true || r.is_expired === 'true',
    expiredReason: r.expired_reason || null,
    violationDeadline: r.violation_deadline,
    discoveryDeadline: r.discovery_deadline
  }
} }];

const d = $input.first().json;
const byViolation = d.dates?.expiredReason === 'violation_date';
const reason = byViolation
  ? `Превышен срок 5 мес. 15 дней с даты нарушения (крайний срок: ${d.dates?.violationDeadline || '—'})`
  : `Превышен срок 20 дней с даты обнаружения (крайний срок: ${d.dates?.discoveryDeadline || '—'})`;
return [{ json: {
  output: `⛔ Привлечение к дисциплинарной ответственности невозможно.\n\n${reason}\n\nОбратитесь к Касмыниной О. или Черепановой Т. для уточнения.`
} }];

const fs = require('fs');
const base = process.env.HR_KNOWLEDGE_DIR
  || '/Users/olegkluev/Documents/Projects/hr-consultant/knowledge';
const checklist = fs.readFileSync(`${base}/progul_checklist.md`, 'utf8');
const tk = fs.readFileSync(`${base}/progul_tk193.md`, 'utf8');
const d = $input.first().json;
return [{ json: { ...d, checklist_content: checklist, tk_content: tk } }];

// TODO: добавить knowledge-файлы и убрать эту заглушку
// Инструкция в sticky note «Добавить новый сценарий» (см. выше)
const d = $input.first().json;
const scenario = d.context?.scenario || 'unknown';
return [{ json: {
  ...d,
  checklist_content: `[ЗАГЛУШКА] Сценарий "${scenario}" не реализован. Добавьте knowledge/${scenario}_checklist.md`,
  tk_content: '[ЗАГЛУШКА] Нормативная база для сценария не загружена'
} }];

// VISION STUB v1 — TODO: заменить на HTTP Request к vision-модели Ollama (qwen2-vl / llava)
// Интерфейс: принимает evidenceDescription, возвращает { vision_stub, analysis }
// При замене: убрать этот нод, добавить HTTP Request к http://127.0.0.1:11434/api/generate
// с моделью qwen2-vl и base64-изображением в поле images[]
const d = $input.first().json;
const desc = d.context?.evidenceDescription || 'Доказательства не предоставлены';
return [{ json: {
  ...d,
  vision_analysis: {
    vision_stub: true,
    analysis: desc,
    _note: 'STUB: заменить на реальную vision-модель Ollama'
  }
} }];

const d = $input.first().json;
const ctx = d.context;
const prompt = `Ты — юридический ассистент по трудовому праву. Твоя задача — кратко и точно сформулировать нарушение трудовых обязанностей со ссылками на нормативные акты.

## Данные о нарушении
Сотрудник: ${ctx.employee?.name || '[не указано]'}
Должность: ${ctx.employee?.position || '[не указано]'}
Подразделение: ${ctx.employee?.department || '[не указано]'}
Дата нарушения: ${ctx.violation?.date || '[не указано]'}
Описание: ${ctx.violation?.description || 'Прогул — отсутствие на рабочем месте без уважительной причины'}
Уважительная причина: ${ctx.respectableReason ? 'Есть: ' + ctx.respectableReasonComment : 'Отсутствует'}

## Чеклист (внутренняя инструкция)
${d.checklist_content}

## Нормативная база
${d.tk_content}

## Задача
Сформулируй нарушение в 2-4 предложениях для включения в служебную записку. Укажи конкретные статьи, пункты. Формат: юридически грамотно, сухо, без лишних слов.
Отвечай ТОЛЬКО формулировкой нарушения, без вводных фраз.`;
return [{ json: { ...d, prompt_rag: prompt } }];

const r = $input.first().json;
const violations = r.response?.trim() || '[Не удалось сформулировать нарушение]';
const prev = $('Vision: анализ доказательств (заглушка)').first().json;
return [{ json: {
  context: prev.context,
  dates: prev.dates,
  checklist_content: prev.checklist_content,
  tk_content: prev.tk_content,
  vision_analysis: prev.vision_analysis,
  violations
} }];

const fs = require('fs');
const base = process.env.HR_TEMPLATES_DIR
  || '/Users/olegkluev/Documents/Projects/hr-consultant/templates';
const template = fs.readFileSync(`${base}/act_progul.md`, 'utf8');
const d = $input.first().json;
const ctx = d.context;
const today = new Date().toLocaleDateString('ru-RU', { day: 'numeric', month: 'long', year: 'numeric' });
const prompt = `Ты — помощник HR-специалиста. Заполни шаблон акта об отсутствии на рабочем месте реальными данными.

## Шаблон
${template}

## Данные для заполнения
Сотрудник (ФИО): ${ctx.employee?.name || '[УТОЧНИТЬ]'}
Должность: ${ctx.employee?.position || '[УТОЧНИТЬ]'}
Подразделение: ${ctx.employee?.department || '[УТОЧНИТЬ]'}
Дата отсутствия: ${ctx.violation?.date || '[УТОЧНИТЬ]'}
Время отсутствия: с ${ctx.violation?.absenceStart || '09:00'} по ${ctx.violation?.absenceEnd || '18:00'}
Попытки связи: ${ctx.contactAttempts || 'Предприняты попытки связаться по телефону и электронной почте'}
Уважительная причина: ${ctx.respectableReason ? ctx.respectableReasonComment : 'не установлена'}
Доказательства: ${d.vision_analysis?.analysis || 'не предоставлены'}
Руководитель (ФИО): ${ctx.manager?.name || '[УТОЧНИТЬ]'}
Должность руководителя: ${ctx.manager?.position || '[УТОЧНИТЬ]'}
Формулировка нарушения: ${d.violations}
Сегодняшняя дата: ${today}

## Инструкция
Заполни ВСЕ {{placeholders}} из шаблона реальными данными. Там где данных нет — поставь [УТОЧНИТЬ].
Верни ТОЛЬКО готовый текст акта, без пояснений и markdown-обёрток.`;
return [{ json: { ...d, prompt_act: prompt } }];

// Для данного сценария акт об отсутствии не требуется
// act_text остаётся пустым — финальный вывод это учтёт
const d = $input.first().json;
return [{ json: { ...d, act_text: '' } }];

const r = $input.first().json;
// Если пришли из Ollama — берём response
// Если пришли из «Акт не нужен» — берём act_text (пустой)
const act_text = r.response?.trim() || r.act_text || '';
const prev = $('Объединить нарушения').first().json;
return [{ json: {
  context: prev.context,
  dates: prev.dates,
  vision_analysis: prev.vision_analysis,
  violations: prev.violations,
  act_text
} }];

const fs = require('fs');
const base = process.env.HR_TEMPLATES_DIR
  || '/Users/olegkluev/Documents/Projects/hr-consultant/templates';
const scenario = $input.first().json.context?.scenario || 'progul';
let templatePath = `${base}/sz_${scenario}.md`;
if (!fs.existsSync(templatePath)) templatePath = `${base}/sz_progul.md`;
const template = fs.readFileSync(templatePath, 'utf8');
const d = $input.first().json;
const ctx = d.context;
const today = new Date().toLocaleDateString('ru-RU', { day: 'numeric', month: 'long', year: 'numeric' });
const prompt = `Ты — помощник HR-специалиста. Заполни шаблон служебной записки реальными данными.

## Шаблон
${template}

## Данные для заполнения
Сотрудник (ФИО): ${ctx.employee?.name || '[УТОЧНИТЬ]'}
Должность: ${ctx.employee?.position || '[УТОЧНИТЬ]'}
Подразделение: ${ctx.employee?.department || '[УТОЧНИТЬ]'}
Дата нарушения: ${ctx.violation?.date || '[УТОЧНИТЬ]'}
Время отсутствия: с ${ctx.violation?.absenceStart || '09:00'} по ${ctx.violation?.absenceEnd || '18:00'}
Руководитель (ФИО): ${ctx.manager?.name || '[УТОЧНИТЬ]'}
Должность руководителя: ${ctx.manager?.position || '[УТОЧНИТЬ]'}
Подразделение руководителя: ${ctx.manager?.department || ctx.employee?.department || '[УТОЧНИТЬ]'}
Уважительная причина: ${ctx.respectableReason ? ctx.respectableReasonComment : 'не установлена'}
Предпринятые меры: ${ctx.contactAttempts || 'Предприняты попытки связаться по телефону и электронной почте'}
Доказательства: ${d.vision_analysis?.analysis || 'не предоставлены'}
Формулировка нарушения: ${d.violations}
Акт об отсутствии: ${d.act_text ? 'составлен' : 'не составлен'}
Сегодняшняя дата: ${today}

## Инструкция
Заполни ВСЕ {{placeholders}} из шаблона реальными данными. Там где данных нет — поставь [УТОЧНИТЬ].
Верни ТОЛЬКО готовый текст служебной записки, без пояснений и markdown-обёрток.`;
return [{ json: { ...d, prompt_sz: prompt } }];

const r = $input.first().json;
const sz_text = r.response?.trim() || '[Не удалось сгенерировать служебную записку]';
const prev = $('Объединить акт').first().json;
const actBlock = prev.act_text
  ? `📋 АКТ ОБ ОТСУТСТВИИ НА РАБОЧЕМ МЕСТЕ

${prev.act_text}

---

`
  : '';
const output = `✅ Документы сформированы!

---

${actBlock}📝 СЛУЖЕБНАЯ ЗАПИСКА

${sz_text}

---

⚠️ Проверьте документы перед отправкой. Поля [УТОЧНИТЬ] требуют вашего заполнения.
После проверки — передайте пакет Черепановой Т. или Касмыниной О.`;
return [{ json: { output, act_text: prev.act_text, sz_text } }];
